import{_ as n,o as a,c as e,ag as p}from"./chunks/framework.BZohXCq9.js";const o=JSON.parse('{"title":"第四章：向量嵌入与分块策略","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/04-embedder.md","filePath":"chapters/04-embedder.md"}'),l={name:"chapters/04-embedder.md"};function i(r,s,c,t,d,b){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="第四章-向量嵌入与分块策略" tabindex="-1">第四章：向量嵌入与分块策略 <a class="header-anchor" href="#第四章-向量嵌入与分块策略" aria-label="Permalink to &quot;第四章：向量嵌入与分块策略&quot;">​</a></h1><blockquote><p>向量嵌入是连接人类语言与机器理解的桥梁。一个记忆系统的检索质量，很大程度上取决于嵌入的质量。memory-lancedb-pro 在嵌入层投入了 1,000 行代码，不是因为嵌入本身复杂，而是因为在生产环境中让嵌入稳定、高效、可靠地工作，需要解决大量工程问题。</p></blockquote><h2 id="_4-1-多提供商抽象层" tabindex="-1">4.1 多提供商抽象层 <a class="header-anchor" href="#_4-1-多提供商抽象层" aria-label="Permalink to &quot;4.1 多提供商抽象层&quot;">​</a></h2><p><code>embedder.ts</code>（800 行）支持 5 种嵌入模型提供商——Jina、OpenAI、Voyage、Gemini、Ollama，每种都有自己的 API 格式、认证方式和响应结构。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L20-60</span></span>
<span class="line"><span>// 所有提供商都实现了 OpenAI 兼容的嵌入 API 格式。</span></span>
<span class="line"><span>// 这不是巧合，而是刻意的架构选择——OpenAI 的</span></span>
<span class="line"><span>// /v1/embeddings 端点已成为事实上的行业标准。</span></span>
<span class="line"><span>// 对于不完全兼容的提供商（如 Ollama 的本地模式），</span></span>
<span class="line"><span>// embedder 内部做了适配层转换。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>为什么不直接使用各提供商的官方 SDK？因为引入 5 个 SDK 会极大膨胀插件的依赖树，而嵌入 API 的调用逻辑非常简单——构建一个 HTTP POST 请求，发送文本，接收向量。自行实现 HTTP 调用让 memory-lancedb-pro 保持了轻量级的依赖结构，也避免了 SDK 版本升级带来的兼容性问题。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L70-100</span></span>
<span class="line"><span>// 每个提供商有预配置的默认 baseUrl 和认证 header 格式。</span></span>
<span class="line"><span>// Jina、OpenAI、Voyage 都使用 Bearer token，</span></span>
<span class="line"><span>// 但 header name 和格式可能微妙不同。</span></span>
<span class="line"><span>// 这些差异都被封装在 embedder 内部，对外只暴露统一接口。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="_4-2-任务感知嵌入-task-aware-embedding" tabindex="-1">4.2 任务感知嵌入（Task-Aware Embedding） <a class="header-anchor" href="#_4-2-任务感知嵌入-task-aware-embedding" aria-label="Permalink to &quot;4.2 任务感知嵌入（Task-Aware Embedding）&quot;">​</a></h2><p>这是 <code>embedder.ts</code> 中最精妙的设计之一。在信息检索领域，<strong>查询文本和文档文本的最优嵌入方式是不同的</strong>。查询通常简短且意图明确；被检索的文档通常较长且信息密集。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L120-170</span></span>
<span class="line"><span>// embed(text: string, task: &#39;retrieval.query&#39; | &#39;retrieval.passage&#39;)</span></span>
<span class="line"><span>//</span></span>
<span class="line"><span>// &#39;retrieval.query&#39; 时强调意图捕捉和语义概括。</span></span>
<span class="line"><span>// &#39;retrieval.passage&#39; 时强调内容覆盖和细节保留。</span></span>
<span class="line"><span>// Jina v3 和 Voyage 原生支持 task 参数；</span></span>
<span class="line"><span>// 对于不支持的模型，embedder 静默忽略 task 参数。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>为什么这个区分如此重要？想象用户问&quot;我之前用过什么数据库？&quot;，记忆库中有&quot;用户在项目中使用了 PostgreSQL 和 Redis&quot;。如果查询嵌入被优化为捕捉意图（&quot;数据库&quot;意味着想知道具体产品），而文档嵌入被优化为保留细节（&quot;PostgreSQL&quot; 和 &quot;Redis&quot; 被标记为数据库类实体），匹配质量就会显著提升。</p><h2 id="_4-3-lru-缓存与-30-分钟-ttl" tabindex="-1">4.3 LRU 缓存与 30 分钟 TTL <a class="header-anchor" href="#_4-3-lru-缓存与-30-分钟-ttl" aria-label="Permalink to &quot;4.3 LRU 缓存与 30 分钟 TTL&quot;">​</a></h2><p>嵌入 API 调用有两个成本：延迟（50-200 毫秒）和费用（按 token 计费）。在记忆系统中，很多文本会被重复嵌入——同一个查询可能被多次使用，同一条记忆在去重阶段可能被反复嵌入比较。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L200-260</span></span>
<span class="line"><span>// LRU 缓存设计：</span></span>
<span class="line"><span>// - 缓存键：hash(text + model + task)</span></span>
<span class="line"><span>// - 缓存值：float32[] 向量</span></span>
<span class="line"><span>// - TTL：30 分钟</span></span>
<span class="line"><span>//</span></span>
<span class="line"><span>// 为什么是 30 分钟？1. 内存占用——每个 1024 维向量约 4KB，</span></span>
<span class="line"><span>// 作为插件不应无限制占用宿主进程内存。</span></span>
<span class="line"><span>// 2. 模型一致性——开发阶段用户可能切换模型，</span></span>
<span class="line"><span>// TTL 确保缓存不会长时间持有过时结果。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>缓存键包含 <code>model</code> 和 <code>task</code> 参数——同一段文本在不同模型下的嵌入完全不同，在不同 task 下也可能不同。如果缓存键只用文本内容，切换模型时会返回错误的缓存结果。</p><h2 id="_4-4-轮询密钥轮换与故障转移" tabindex="-1">4.4 轮询密钥轮换与故障转移 <a class="header-anchor" href="#_4-4-轮询密钥轮换与故障转移" aria-label="Permalink to &quot;4.4 轮询密钥轮换与故障转移&quot;">​</a></h2><p>单个 API Key 有速率限制，高频使用场景下容易触达上限。memory-lancedb-pro 支持配置多个 API Key，通过轮询（Round-Robin）策略分散负载。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L280-340</span></span>
<span class="line"><span>// getNextKey(): string {</span></span>
<span class="line"><span>//   const key = this.keys[this.keyIndex % this.keys.length];</span></span>
<span class="line"><span>//   this.keyIndex++;</span></span>
<span class="line"><span>//   return key;</span></span>
<span class="line"><span>// }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>更关键的是故障转移逻辑：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L350-410</span></span>
<span class="line"><span>// 当请求返回 401 或 429 时，将 key 标记为&quot;暂时不可用&quot;，</span></span>
<span class="line"><span>// 自动切换到下一个 key 重试。</span></span>
<span class="line"><span>// - 401 错误：标记 60 分钟（可能是 key 被吊销）</span></span>
<span class="line"><span>// - 429 错误：标记 60 秒（速率限制通常很快恢复）</span></span>
<span class="line"><span>// 如果所有 key 都不可用，重置所有标记并用第一个 key 重试。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这段逻辑只有几十行代码，但生产价值巨大。没有它，一个 API Key 的临时失效就会导致整个记忆系统停摆。</p><h2 id="_4-5-自动维度检测" tabindex="-1">4.5 自动维度检测 <a class="header-anchor" href="#_4-5-自动维度检测" aria-label="Permalink to &quot;4.5 自动维度检测&quot;">​</a></h2><p>不同模型输出不同维度的向量——OpenAI text-embedding-3-small 是 1536 维，Jina v3 是 1024 维。创建 LanceDB 表时需要知道维度才能正确定义 schema。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L430-490</span></span>
<span class="line"><span>// 系统内置 25+ 常见模型的维度映射表。</span></span>
<span class="line"><span>// const KNOWN_DIMENSIONS: Record&lt;string, number&gt; = {</span></span>
<span class="line"><span>//   &#39;text-embedding-3-small&#39;: 1536,</span></span>
<span class="line"><span>//   &#39;jina-embeddings-v3&#39;: 1024,</span></span>
<span class="line"><span>//   &#39;voyage-3&#39;: 1024,</span></span>
<span class="line"><span>//   &#39;text-embedding-004&#39;: 768,</span><span>  // Gemini</span></span>
<span class="line"><span>//</span><span>   // ... 25+ 模型</span></span>
<span class="line"><span>// };</span></span>
<span class="line"><span>// 对于未知模型，发送探测请求从响应中获取实际维度。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>为什么不让用户手动指定维度？因为这是容易出错的配置项——记错维度、切换模型时忘记更新。自动检测消除了这类错误，同时配置中仍保留 <code>dimensions</code> 字段允许显式覆盖。</p><h2 id="_4-6-语义分块策略" tabindex="-1">4.6 语义分块策略 <a class="header-anchor" href="#_4-6-语义分块策略" aria-label="Permalink to &quot;4.6 语义分块策略&quot;">​</a></h2><p><code>chunker.ts</code>（200+ 行）处理长文本切分。最朴素的方式是按固定字符数截断，但这经常在句子甚至词语中间断开。memory-lancedb-pro 采用<strong>语义感知的句子边界切分</strong>。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/chunker.ts L20-60</span></span>
<span class="line"><span>// 切分算法：</span></span>
<span class="line"><span>// 1. 使用正则表达式识别句子边界（区分 &quot;Mr.&quot; 和句号等）</span></span>
<span class="line"><span>// 2. 贪心地将句子合并为 chunk，直到达到目标长度</span></span>
<span class="line"><span>// 3. 新 chunk 的开头包含前一个 chunk 的最后 N 个句子（重叠）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>为什么需要重叠？</strong> 考虑：&quot;用户提到他去年搬到了上海。他说上海的天气让他很不适应。&quot;无重叠地切分后，第二个 chunk 失去了&quot;他&quot;的指代上下文。重叠确保每个 chunk 携带足够的上下文信息。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/chunker.ts L70-110</span></span>
<span class="line"><span>// minChunkLength 防止产生过短的 chunk。</span></span>
<span class="line"><span>// 过短文本（如&quot;好的。&quot;）嵌入后的向量信息密度很低，</span></span>
<span class="line"><span>// 会在检索时产生大量误匹配——短文本的嵌入向量</span></span>
<span class="line"><span>// 往往落在高维空间的&quot;公共区域&quot;，</span></span>
<span class="line"><span>// 与很多查询都有中等相似度但没有真正的相关性。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="_4-7-并行分块嵌入与向量平均" tabindex="-1">4.7 并行分块嵌入与向量平均 <a class="header-anchor" href="#_4-7-并行分块嵌入与向量平均" aria-label="Permalink to &quot;4.7 并行分块嵌入与向量平均&quot;">​</a></h2><p>多个 chunk 使用并行请求生成嵌入，然后通过向量平均生成最终记忆向量。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/chunker.ts L130-180</span></span>
<span class="line"><span>// const chunkVectors = await Promise.all(</span></span>
<span class="line"><span>//   chunks.map(chunk =&gt; embedder.embed(chunk, &#39;retrieval.passage&#39;))</span></span>
<span class="line"><span>// );</span></span>
<span class="line"><span>//</span><span> // 向量平均：简单平均在大多数检索基准上的表现</span></span>
<span class="line"><span>//</span><span> // 与更复杂的聚合方法差距不大，但实现成本显著更低。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/chunker.ts L185-210</span></span>
<span class="line"><span>// 实际实现中使用并发限制（通常 5-10），</span></span>
<span class="line"><span>// 通过信号量模式确保最多 N 个嵌入请求同时在飞行中。</span></span>
<span class="line"><span>// 为什么不用批量嵌入接口？不是所有提供商都支持，</span></span>
<span class="line"><span>// 并发单条请求 + 信号量控制在所有提供商上都能可靠工作。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="_4-8-嵌入层的优雅降级" tabindex="-1">4.8 嵌入层的优雅降级 <a class="header-anchor" href="#_4-8-嵌入层的优雅降级" aria-label="Permalink to &quot;4.8 嵌入层的优雅降级&quot;">​</a></h2><p>嵌入层有一个<strong>故意缺失</strong>的降级路径——跨提供商降级：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L550-600</span></span>
<span class="line"><span>// 嵌入层没有&quot;Jina 不可用时自动切换到 OpenAI&quot;的设计。</span></span>
<span class="line"><span>// 不同提供商的嵌入向量处于完全不同的向量空间，</span></span>
<span class="line"><span>// 混用会导致检索结果完全不可靠。</span></span>
<span class="line"><span>// 与其给出错误的结果，不如明确地失败。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这体现了工程成熟度：所有记忆和查询必须使用同一个嵌入模型，否则向量空间不一致，相似度计算毫无意义。悄悄切换提供商比不返回结果更糟糕——用户会认为系统正常工作，但实际得到的是垃圾数据。</p><h2 id="_4-9-embedder-与-chunker-的协作模式" tabindex="-1">4.9 embedder 与 chunker 的协作模式 <a class="header-anchor" href="#_4-9-embedder-与-chunker-的协作模式" aria-label="Permalink to &quot;4.9 embedder 与 chunker 的协作模式&quot;">​</a></h2><p>两者的协作关系是单向依赖：chunker 依赖 embedder，但 embedder 不知道 chunker 的存在。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/embedder.ts L620-650</span></span>
<span class="line"><span>// 调用链路：</span></span>
<span class="line"><span>// index.ts → 判断文本长度是否需要分块</span></span>
<span class="line"><span>//   → 需要：chunker.chunk(text)，对每个 chunk 调用 embedder.embed()</span></span>
<span class="line"><span>//   → 不需要：直接 embedder.embed(text)</span></span>
<span class="line"><span>// 分块阈值由配置决定（默认约 512 tokens）。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>embedder 保持单一职责——&quot;给我文本，还你向量&quot;。分块逻辑、向量聚合在 chunker 中处理，何时分块由编排层决定。每个组件只关心自己的领域，通过清晰的接口协作。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p><code>embedder.ts</code> 和 <code>chunker.ts</code> 共同构成了 memory-lancedb-pro 的嵌入层，总计约 1,000 行代码。嵌入层通过 OpenAI 兼容的 API 格式抽象了 5 种提供商，通过任务感知嵌入提升检索匹配质量，通过 LRU 缓存和轮询密钥轮换解决了性能和可靠性问题，通过自动维度检测降低了配置出错的可能性。chunker 采用语义感知的句子边界切分和可配置重叠策略，结合并行嵌入与向量平均，在保持语义完整性的同时高效处理长文本。嵌入层故意不支持跨提供商降级，这个看似&quot;缺陷&quot;的设计决策，恰恰体现了对向量空间一致性这一核心约束的深刻理解。</p>`,44)])])}const m=n(l,[["render",i]]);export{o as __pageData,m as default};
